/// <summary>
/// Asset Depreciation import
/// </summary>
public class ETG_Acu_AssetDepreciationTransImport extends ETG_Acu_DataImportBase
{
    LedgerJournalId         journalNum;

}

Method.Source:
public static void main(Args args)
{
    ETG_Acu_AssetDepreciationTransImport  assetDepreciationTrans;

    assetDepreciationTrans = ETG_Acu_AssetDepreciationTransImport::construct();

    if (assetDepreciationTrans.prompt())
    {
        assetDepreciationTrans.runOperation();
    }
}

public static ETG_Acu_AssetDepreciationTransImport construct()
{
    return new ETG_Acu_AssetDepreciationTransImport();
}

/// <summary>
/// Describes whether the class is designed for execution in a new session.
/// </summary>
/// <returns>
/// true if the class is designed for execution the operation in a new session; otherwise, false.
/// </returns>
protected boolean canRunInNewSession()
{
    return false;
}

protected void processData(container _con)
{
    AssetJournalV2Entity    assetDepreciationJournal;
    NumberSeq               numberSeq;
    CurrencyExchangeHelper  currencyExchHelper;
    if (!journalNum)
    {
        numberSeq = NumberSeq::newGetNum(LedgerParameters::numRefJournalNum());

        journalNum = numberSeq.num();
    }

    assetDepreciationJournal.JournalBatchNumber              = journalNum;
    assetDepreciationJournal.LineNumber                      = conpeek(_con, 2);
    assetDepreciationJournal.AccountDisplayValue             = conpeek(_con, 3);
    assetDepreciationJournal.AccountType                     = conpeek(_con, 4);
    assetDepreciationJournal.CreditAmount                    = conpeek(_con, 5);
    assetDepreciationJournal.CurrencyCode                    = conpeek(_con, 6);
    assetDepreciationJournal.DebitAmount                     = conpeek(_con, 7);
    //assetDepreciationJournal.DefaultDimensionDisplayValue    = conpeek(_con, 8);
    assetDepreciationJournal.Description                     = conpeek(_con, 9);
    assetDepreciationJournal.ExchangeRate                    = conpeek(_con, 10);
    assetDepreciationJournal.JournalNameId                   = conpeek(_con, 11);
    assetDepreciationJournal.OffsetAccountDisplayValue       = conpeek(_con, 12) + enum2Str(dimensionParameters.DimensionSegmentDelimiter)
                                                                + conPeek(_con, 24) + enum2Str(dimensionParameters.DimensionSegmentDelimiter)
                                                                + conPeek(_con, 22) + enum2Str(dimensionParameters.DimensionSegmentDelimiter)
                                                                + conPeek(_con, 26) + enum2Str(dimensionParameters.DimensionSegmentDelimiter)
                                                                + conPeek(_con, 25) + enum2Str(dimensionParameters.DimensionSegmentDelimiter)
                                                                + conPeek(_con, 20) + enum2Str(dimensionParameters.DimensionSegmentDelimiter)
                                                                + conPeek(_con, 23) + enum2Str(dimensionParameters.DimensionSegmentDelimiter)
                                                                + conPeek(_con, 21);

    assetDepreciationJournal.OffsetAccountType               = conpeek(_con, 13);
    assetDepreciationJournal.PostingLayer                    = conpeek(_con, 14);
    assetDepreciationJournal.Text                            = conpeek(_con, 15);
    assetDepreciationJournal.TransactionType                 = conpeek(_con, 16);
    assetDepreciationJournal.TransDate                       = str2Date(conpeek(_con, 17), 123);
    assetDepreciationJournal.BookId                          = conpeek(_con, 18);
    assetDepreciationJournal.Voucher                         = conpeek(_con, 19);

    // BusinessUnit (20)	Contract (21)	Department (22)	Intercompany (23)	Plant_Warehouse_Office (24)	Product_Service (25)	Trader_Employee (26)
    // |Plant_Warehouse_Office|Department|Trader_Employee|Product_Service|BusinessUnit|Intercompany|Contract

    assetDepreciationJournal.DefaultDimensionDisplayValue  = conPeek(_con, 24) + enum2Str(dimensionParameters.DimensionSegmentDelimiter)
                                                + conPeek(_con, 22) + enum2Str(dimensionParameters.DimensionSegmentDelimiter)
                                                + conPeek(_con, 26) + enum2Str(dimensionParameters.DimensionSegmentDelimiter)
                                                + conPeek(_con, 25) + enum2Str(dimensionParameters.DimensionSegmentDelimiter)
                                                + conPeek(_con, 20) + enum2Str(dimensionParameters.DimensionSegmentDelimiter)
                                                + conPeek(_con, 23) + enum2Str(dimensionParameters.DimensionSegmentDelimiter)
                                                + conPeek(_con, 21);

    if (assetDepreciationJournal.CreditAmountReportingCurrency == 0)
    {
        currencyExchHelper = CurrencyExchangeHelper::newExchangeDate(Ledger::current(),assetDepreciationJournal.TransDate);

        assetDepreciationJournal.CreditAmountReportingCurrency  =   currencyExchHelper.calculateTransactionCurrencyToReportingCurrency(Ledger::accountingCurrency(), assetDepreciationJournal.CreditAmount, true);
    }

    if (assetDepreciationJournal.DebitAmountReportingCurrency == 0)
    {
        currencyExchHelper = CurrencyExchangeHelper::newExchangeDate(Ledger::current(),assetDepreciationJournal.TransDate);

        assetDepreciationJournal.DebitAmountReportingCurrency  =   currencyExchHelper.calculateTransactionCurrencyToReportingCurrency(Ledger::accountingCurrency(), assetDepreciationJournal.DebitAmount, true);
    }

    assetDepreciationJournal.insert();
}

/// <summary>
///Import inventory site
/// </summary>
/// <returns>Caption</returns>
public ClassDescription caption()
{
    ClassDescription ret;

    ret = "@ETG_ENG_Labels:ImpAssetDep";

    return ret;
}
